   392→export interface OffersReducerProps {
   393→  isLoadingOffers: boolean;
   394→  isError: boolean;
   395→  elegible: boolean;
   396→  data: undefined | Partial<OffersResponseData['data']>;
   397→  isBlockedToUpdateDueDates: boolean;
   398→  debtValue?: number;
   399→  intention: {
