   419→export type State = OffersReducerProps;
   420→
   421→export const initialState: OffersReducerProps = {
   422→  isLoadingOffers: false,
   423→  isError: false,
   424→  elegible: false,
   425→  data: undefined,
   426→  isBlockedToUpdateDueDates: false,
   427→  updateData: {
   428→    isError: false,
   429→    isLoading: false,
   430→  },
   431→  intention: {
   432→    isLoading: false,
   433→    isError: false,
   434→  },
   435→  getIntention: {
   436→    isLoading: false,
   437→    isError: false,
   438→  },
   439→  getSubscribedOffer: {
   440→    isLoading: false,
   441→    isError: false
   442→  }
   443→};
   444→
   445→export const offersReducer = createReducer(initialState, {
   446→  [OffersTypes.REQUEST_OFFERS](state: State) {
   447→    return {
   448→      ...state,
   449→      isLoadingOffers: true,
   450→      isError: false,
   451→    };
   452→  },
   453→  [OffersTypes.SUCCESS_OFFERS](
   454→    state: State,
   455→    {
   456→      data,
   457→      elegible,
   458→      isBlockedToUpdateDueDates,
   459→      debtValue,
   460→    }: {
   461→      data: OffersResponseData['data'];
   462→      elegible: boolean;
   463→      isBlockedToUpdateDueDates: boolean;
   464→      debtValue?: number;
   465→    },
   466→  ) {
   467→    return {
   468→      ...state,
   469→      data,
   470→      elegible,
   471→      isLoadingOffers: false,
   472→      isError: false,
   473→      isBlockedToUpdateDueDates,
   474→      debtValue,
   475→    };
   476→  },
   477→  [OffersTypes.FAILED](state: State) {
   478→    return {
   479→      ...state,
   480→      isLoadingOffers: false,
   481→      isError: true,
   482→    };
   483→  },
   484→  [OffersTypes.SET_FIRST_ACESS_DATE](
   485→    state: State,
   486→    { data: { firstDateAccessClient } }: { data: OfferDataPut },
   487→  ): State {
   488→    return {
   489→      ...state,
   490→      data: {
   491→        ...state.data,
   492→        offers: [
   493→          {
   494→            ...state.data?.offers?.[0],
   495→            firstDateAccessClient: firstDateAccessClient,
   496→          },
   497→        ],
   498→      },
   499→    };
   500→  },
   501→  [OffersTypes.SET_FRAUD_BIOMETRIC](
   502→    state: State,
   503→    { data: { fraudBiometrics } }: { data: OfferDataPut },
   504→  ): State {
   505→    return {
   506→      ...state,
   507→      data: {
   508→        ...state.data,
   509→        offers: [
   510→          { ...state.data?.offers?.[0], fraudBiometrics: fraudBiometrics },
   511→        ],
   512→      },
   513→    };
   514→  },
   515→  [OffersTypes.SET_FRAUD_QUOD](
   516→    state: State,
   517→    { data: { fraudQuod } }: { data: OfferDataPut },
   518→  ): State {
   519→    return {
   520→      ...state,
   521→      data: {
   522→        ...state.data,
   523→        offers: [{ ...state.data?.offers?.[0], fraudQuod: fraudQuod }],
   524→      },
   525→    };
   526→  },
   527→  [OffersTypes.PUT_OFFERS_DATA](state: State): State {
   528→    return {
   529→      ...state,
   530→      updateData: {
   531→        ...state.updateData,
   532→        isLoading: true,
   533→      },
   534→    };
   535→  },
   536→  [OffersTypes.PUT_SUCCESS_OFFERS](state: State): State {
   537→    return {
   538→      ...state,
   539→      updateData: {
   540→        ...state.updateData,
   541→        isLoading: false,
   542→        isError: false,
   543→      },
   544→    };
   545→  },
   546→  [OffersTypes.PUT_ERROR_OFFERS](state: State): State {
   547→    return {
   548→      ...state,
   549→      updateData: {
   550→        ...state.updateData,
   551→        isLoading: false,
   552→        isError: true,
   553→      },
   554→    };
   555→  },
   556→  [OffersTypes.CLEAR](): State {
   557→    return initialState;
   558→  },
   559→  [OffersTypes.CLEAR_LOADING](state: State): State {
   560→    return {
   561→      ...state,
   562→      isLoadingOffers: false,
   563→      updateData: {
   564→        ...state.updateData,
   565→        isLoading: false,
   566→      },
   567→    };
   568→  },
   569→  [OffersTypes.REGISTER_INTENTION_REQUEST](state: State) {
   570→    return {
   571→      ...state,
   572→      intention: {
   573→        ...state.intention,
   574→        isLoading: true,
   575→        isError: false,
   576→      },
   577→    };
   578→  },
   579→  [OffersTypes.REGISTER_INTENTION_SUCCESS](state: State) {
   580→    return {
   581→      ...state,
   582→      intention: {
   583→        ...state.intention,
   584→        isLoading: false,
   585→        isError: false,
   586→      },
   587→    };
   588→  },
   589→  [OffersTypes.REGISTER_INTENTION_ERROR](
   590→    state: State,
   591→    action: { type: string; error: string },
   592→  ) {
   593→    return {
   594→      ...state,
   595→      intention: {
   596→        ...state.intention,
   597→        isLoading: false,
   598→        isError: true,
   599→      },
   600→    };
   601→  },
   602→  [OffersTypes.GET_INTENTION_REQUEST](state: State) {
   603→    return {
   604→      ...state,
   605→      getIntention: {
   606→        data: undefined,
   607→        isLoading: true,
   608→        isError: false,
   609→      },
   610→    };
   611→  },
   612→  [OffersTypes.GET_INTENTION_SUCCESS](
   613→    state: State,
   614→    { data }: { type: string; data: IntentionData[] },
   615→  ): State {
   616→    return {
   617→      ...state,
   618→      getIntention: {
   619→        data,
   620→        isLoading: false,
   621→        isError: false,
   622→      },
   623→    };
   624→  },
   625→  [OffersTypes.GET_INTENTION_ERROR](state: State) {
   626→    return {
   627→      ...state,
   628→      getIntention: {
   629→        data: undefined,
   630→        isLoading: false,
   631→        isError: true,
   632→      },
   633→    };
   634→  },
   635→  [OffersTypes.GET_SUBSCRIBED_OFFER_REQUEST](state: State) {
   636→    return {
   637→      ...state,
   638→      getSubscribedOffer: {
   639→        data: undefined,
   640→        isLoading: true,
   641→        isError: false,
   642→      }
   643→    }
   644→  },
   645→  [OffersTypes.GET_SUBSCRIBED_OFFER_SUCCESS](
   646→    state: State,
   647→    { data }: { data: { product: productsBenefits, promotions: PromotionUI[], hasKeycloak: boolean } }
   648→  ): State {
   649→    return {
   650→      ...state,
   651→      getSubscribedOffer: {
   652→        data,
   653→        isLoading: false,
   654→        isError: false,
   655→      }
   656→    };
   657→  },
   658→  [OffersTypes.GET_SUBSCRIBED_OFFER_ERROR](state: State) {
   659→    return {
   660→      ...state,
   661→      getSubscribedOffer: {
   662→        data: undefined,
   663→        isLoading: false,
   664→        isError: true,
   665→      }
   666→    };
   667→  },
   668→});
