     1→import { BenefitListLargeItem, BenefitListProps } from './Models';
     2→import isPlainObject from 'lodash/isPlainObject';
     3→
     4→const ICON_COLOR = 'INTENSE_COLOR_05';
     5→
     6→export function formatBenefitListItems(
     7→  benefits: BenefitListProps['benefits'] | null,
     8→  onPress: BenefitListProps['itemOnPress'] | null,
     9→) {
    10→  let benefitsList: Array<{ key: string; benefit: Benefit }> | null = null;
    11→
    12→  if (benefits) {
    13→    if (Array.isArray(benefits)) {
    14→      benefitsList = benefits.map((b, index) => ({
    15→        key: String(index),
    16→        benefit: b,
    17→      }));
    18→    } else if (isPlainObject(benefits)) {
    19→      benefitsList = Object.entries(benefits).map(([key, benefit]) => ({
    20→        key,
    21→        benefit,
    22→      }));
    23→    }
    24→  }
    25→
    26→  if (!benefitsList) return [];
    27→  const parsedList: BenefitListLargeItem[] = [];
    28→
    29→  for (const { key, benefit } of benefitsList) {
    30→    const {
    31→      idTitle,
    32→      idText,
    33→      idFullTitle,
    34→      idFullText,
    35→      idIcone,
    36→      idType,
    37→      idHideOnboarding,
    38→      idPriority,
    39→    } = benefit;
    40→
    41→    if (idHideOnboarding?.text === 'TRUE') continue;
    42→
    43→    const title = idTitle?.text;
    44→    const icon = idIcone?.text as BenefitListLargeItem['icon'];
    45→    const type = idType?.text;
    46→    const text = idText?.text;
    47→    const fullTitle = idFullTitle?.text;
    48→    const fullText = idFullText?.text;
    49→    const description = idText?.text;
    50→    const priority = Number(idPriority?.text ?? 99999);
    51→    const iconColor = ICON_COLOR;
    52→
    53→    if (!(fullText && title && text && fullTitle && icon && type && icon)) {
    54→      console.warn(`Invalid benefit found: ${benefit.idFullTitle?.text}`);
    55→      continue;
    56→    }
    57→
    58→    parsedList.push({
    59→      title,
    60→      icon,
    61→      description,
    62→      onPress: () => onPress?.(benefit, key), // ✅ AQUI
    63→      iconColor,
    64→      priority,
    65→      showIconRight: true,
    66→      rightIconColor: undefined,
    67→    });
    68→  }
    69→
    70→  return parsedList.sort((a, b) => a.priority - b.priority);
    71→}

